import type { ScenarioQuestion } from "./types";

export const interviewPreparationBehavioral: ScenarioQuestion[] = [
  { id: "sq-ip-beh-1", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "A patient's family member becomes angry about the wait time and starts yelling at you at the nurses' station.", question: "How would you handle an angry family member who is creating a disturbance?", exampleAnswer: "I would remain calm and acknowledge their frustration. I'd say, 'I understand the wait has been long, and I can see how frustrating that must be.' I would offer to move to a private area to discuss their concerns, provide an update on the patient's status, and contact the charge nurse if the situation escalated. Maintaining empathy while setting professional boundaries is key.", feedback: "Strong answers show de-escalation skills and empathy without being defensive.", starBreakdown: { situation: "Family member yelling at nurses' station about long wait", task: "De-escalate the situation while maintaining professionalism", action: "Acknowledged frustration, moved to private area, provided status update", result: "Family member calmed down, felt heard, and wait was more tolerable" }, difficulty: "beginner" },
  { id: "sq-ip-beh-2", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "During a busy shift, you notice a colleague making a medication error—they are about to administer the wrong dose of insulin.", question: "What would you do if you witnessed a colleague about to make a medication error?", exampleAnswer: "I would immediately but discreetly intervene to prevent the error. I'd approach my colleague privately and say, 'Let me double-check this dose with you.' After preventing the error, I would document it according to facility protocol and encourage my colleague to report it. Patient safety always takes priority over workplace comfort.", feedback: "Emphasize patient safety first, then address the colleague privately and supportively.", starBreakdown: { situation: "Witnessed colleague preparing wrong insulin dose", task: "Prevent the medication error while maintaining collegial relationship", action: "Intervened discreetly, helped verify correct dose, encouraged reporting", result: "Error prevented, patient received correct medication, colleague appreciated the catch" }, difficulty: "beginner" },
  { id: "sq-ip-beh-3", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You are assigned to a patient who speaks a language you do not understand, and no interpreter is immediately available.", question: "How would you provide safe care to a patient when you face a language barrier?", exampleAnswer: "I would first use any available translation technology such as the hospital's phone interpreter service or translation app. I would use simple gestures and visual aids for immediate safety needs. I would document the communication barrier and request an in-person interpreter. Patient safety assessments would be done more frequently to compensate for the communication gap.", feedback: "Good answers show resourcefulness and commitment to equitable care regardless of language barriers.", starBreakdown: { situation: "Assigned patient who spoke only Mandarin with no interpreter available", task: "Provide safe, effective care despite the language barrier", action: "Used phone interpreter line, visual pain scale, gesture communication, requested in-person interpreter", result: "Patient received appropriate pain management and felt cared for; interpreter arrived within 2 hours" }, difficulty: "beginner" },
  { id: "sq-ip-beh-4", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "Your preceptor gives you feedback that your documentation is too slow and you need to improve your charting speed.", question: "How would you respond to constructive criticism about your documentation speed?", exampleAnswer: "I would thank my preceptor for the honest feedback and ask for specific suggestions on how to improve. I'd practice those techniques, perhaps using templates or real-time documentation during assessments. I would set a goal for improvement and check back with my preceptor in a week.", feedback: "Shows growth mindset, receptiveness to feedback, and proactive improvement planning.", starBreakdown: { situation: "Preceptor noted documentation was taking too long", task: "Improve charting efficiency without sacrificing accuracy", action: "Asked for specific tips, used charting templates, practiced real-time documentation", result: "Reduced charting time by 40% within two weeks while maintaining thorough documentation" }, difficulty: "beginner" },
  { id: "sq-ip-beh-5", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "A physician gives you a verbal order that you believe may be incorrect or harmful to the patient.", question: "What would you do if you received a questionable order from a physician?", exampleAnswer: "I would clarify the order by reading it back and asking the physician to confirm. If I still had concerns, I would cite the patient's relevant clinical data. If the physician insists and I believe it could harm the patient, I would follow the chain of command and escalate to the charge nurse or supervisor. I would never administer something I believe is unsafe.", feedback: "Demonstrates advocacy for patient safety and appropriate use of chain of command.", starBreakdown: { situation: "Physician ordered medication dose that seemed too high for patient's renal function", task: "Verify the order to ensure patient safety", action: "Clarified with physician, cited lab values, consulted pharmacist", result: "Dose was adjusted to be renally appropriate, preventing potential toxicity" }, difficulty: "beginner" },
  { id: "sq-ip-beh-6", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You are caring for a terminally ill patient whose family wants aggressive treatment, but the patient has expressed a desire for comfort care only.", question: "How would you navigate conflicting wishes between a patient and their family?", exampleAnswer: "I would ensure the patient's wishes are clearly documented and that they have decision-making capacity. I would advocate for the patient's autonomy while showing empathy to the family. I'd facilitate a family meeting with the healthcare team, social worker, and chaplain if appropriate to help the family understand the patient's perspective.", feedback: "Strong answers balance patient autonomy with family compassion and use interdisciplinary resources.", starBreakdown: { situation: "Terminal cancer patient wanted comfort care; family insisted on aggressive treatment", task: "Honor the patient's wishes while supporting the family", action: "Arranged family conference with palliative care team, social worker, and chaplain", result: "Family understood and accepted the patient's wishes; patient received comfort care with dignity" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-7", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You are working a 12-hour night shift and realize at 3 AM that you forgot to give a patient their scheduled 10 PM medication.", question: "How would you handle discovering you missed administering a scheduled medication?", exampleAnswer: "I would immediately assess the patient for any adverse effects from the missed dose. I would contact the provider to report the missed medication and get guidance. I would complete an incident report, document the missed dose, and implement strategies to prevent future missed doses such as setting alarms or improving my workflow.", feedback: "Honest self-reporting, patient assessment, and process improvement show professional maturity.", starBreakdown: { situation: "Discovered at 3 AM that a scheduled 10 PM blood pressure medication was not given", task: "Address the missed dose and ensure patient safety", action: "Assessed patient, notified physician, administered late dose per order, filed incident report", result: "Patient remained stable, process improvement led to zero missed medications going forward" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-8", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "A patient who is alert and oriented refuses a blood transfusion due to religious beliefs, but their hemoglobin is critically low.", question: "How would you handle a competent patient refusing a life-saving treatment?", exampleAnswer: "I would respect the patient's right to refuse treatment while ensuring they fully understand the risks. I would have a thorough conversation about the potential consequences, document their refusal, notify the physician, and explore alternative treatments. The patient's autonomy must be respected even when we disagree with their decision.", feedback: "Demonstrates respect for patient autonomy, thorough informed consent process, and ethical practice.", starBreakdown: { situation: "Jehovah's Witness patient with hemoglobin of 5.2 refusing blood transfusion", task: "Respect patient autonomy while ensuring informed decision-making", action: "Ensured patient understood risks, documented refusal, explored alternatives like EPO and iron", result: "Patient's wishes were respected, alternative therapies initiated, patient recovered conservatively" }, difficulty: "advanced" },
  { id: "sq-ip-beh-9", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You overhear two nurses gossiping about a patient's personal medical information in the break room.", question: "What would you do if you witnessed a HIPAA violation by colleagues?", exampleAnswer: "I would address it immediately but professionally. I'd say, 'I know you might not realize, but discussing patient information in the break room could be a HIPAA concern.' If they continued, I would report it to my charge nurse. Protecting patient privacy is a legal and ethical obligation.", feedback: "Shows willingness to address violations directly while maintaining collegial relationships.", starBreakdown: { situation: "Two colleagues discussing patient's HIV status in the break room", task: "Stop the HIPAA violation and protect patient privacy", action: "Politely reminded colleagues about privacy rules, followed up with charge nurse", result: "Colleagues stopped immediately, unit held a refresher on HIPAA compliance" }, difficulty: "beginner" },
  { id: "sq-ip-beh-10", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "During your orientation, you feel that your preceptor is not providing enough guidance and often leaves you to figure things out alone.", question: "How would you handle feeling unsupported by your preceptor?", exampleAnswer: "I would have an honest conversation with my preceptor about needing more hands-on guidance. If the situation didn't improve, I would speak with my nurse educator about getting additional support. Safety should never be compromised during orientation.", feedback: "Shows self-advocacy, clear communication, and appropriate escalation.", starBreakdown: { situation: "Preceptor frequently left me unsupervised during second week of orientation", task: "Get adequate support to ensure safe patient care", action: "Had honest conversation with preceptor, discussed concerns with nurse educator", result: "Preceptor adjusted their approach, received additional clinical support" }, difficulty: "beginner" },
  { id: "sq-ip-beh-11", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You are assigned five patients and a sixth admission arrives. You already feel overwhelmed.", question: "What would you do when you feel your patient assignment is unsafe?", exampleAnswer: "I would quickly reprioritize my current patients and identify tasks that can be delegated. I would speak with my charge nurse and clearly communicate my concerns using objective data about patient acuity. I would document my concern through the appropriate channels and request additional support.", feedback: "Demonstrates assertive communication, use of objective data, and appropriate escalation.", starBreakdown: { situation: "Managing five high-acuity patients when a sixth admission was assigned", task: "Advocate for safe staffing and patient safety", action: "Communicated specific concerns to charge nurse with objective data, requested support", result: "Charge nurse reassigned one stable patient, admission was safely managed" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-12", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "A patient tells you they are thinking about ending their life.", question: "How would you respond to a patient expressing suicidal ideation?", exampleAnswer: "I would stay calm, sit down with the patient, and listen without judgment. I would ask direct questions to assess risk level. I would ensure the patient's safety by removing potential means of harm, immediately notify the provider, request a psychiatric consult, and stay with the patient or arrange for a sitter.", feedback: "Shows compassion, proper risk assessment, and immediate safety interventions.", starBreakdown: { situation: "Post-surgical patient stated they did not want to be alive anymore", task: "Assess suicide risk and ensure immediate patient safety", action: "Asked direct screening questions, removed sharps, stayed with patient, called psychiatric consult", result: "Patient placed on 1:1 observation, psychiatry provided intervention, patient started treatment" }, difficulty: "advanced" },
  { id: "sq-ip-beh-13", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You discover that a fellow nurse has been coming to work smelling of alcohol.", question: "What is your responsibility if you suspect a colleague is impaired at work?", exampleAnswer: "Patient safety is my top priority, so I would report my concerns to the charge nurse and nurse manager immediately. I would document specific, objective observations. I would not confront the colleague directly or gossip about it. I would trust leadership to handle the situation while ensuring patients are safe.", feedback: "Prioritizes patient safety, uses objective documentation, and follows chain of command.", starBreakdown: { situation: "Noticed a colleague smelled of alcohol on two consecutive shifts", task: "Protect patients while handling the situation responsibly", action: "Documented objective observations, reported to charge nurse and manager privately", result: "Colleague was referred to employee assistance program and patients remained safe" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-14", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "A patient's daughter demands to speak with the doctor immediately, but the doctor is in surgery.", question: "How would you manage a family member's urgent request when the physician is unavailable?", exampleAnswer: "I would acknowledge the daughter's concern, explain that the physician is currently unavailable, and provide a realistic timeframe. I would offer to answer questions within my scope, relay specific concerns to the physician, and arrange a callback or meeting.", feedback: "Balances family needs with realistic expectations and appropriate resource utilization.", starBreakdown: { situation: "Patient's daughter upset about care plan changes, demanding immediate physician meeting", task: "Address concerns while managing expectations", action: "Validated feelings, answered scope-appropriate questions, arranged callback", result: "Daughter felt heard, physician returned call within the hour" }, difficulty: "beginner" },
  { id: "sq-ip-beh-15", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You are in the middle of a sterile procedure when another patient's call light goes off.", question: "How would you manage competing patient needs when you cannot leave?", exampleAnswer: "I would use my call system to contact the nurses' station and ask a colleague to check on the patient. I would finish the procedure safely without rushing. Once complete, I would follow up with the other patient to ensure their need was met.", feedback: "Shows ability to prioritize, delegate, and use available resources effectively.", starBreakdown: { situation: "Inserting a Foley catheter when another patient's call light activated", task: "Ensure both patients receive timely, safe care", action: "Used call system to request CNA assistance, completed procedure, followed up", result: "Both patients received appropriate care without compromising sterile technique" }, difficulty: "beginner" },
  { id: "sq-ip-beh-16", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "A colleague asks you to cover for them while they take an extended unauthorized break.", question: "What would you do if a coworker asked you to cover for them inappropriately?", exampleAnswer: "I would decline professionally and suggest they speak with the charge nurse if they need additional time. I would not judge them but would need to prioritize patient safety. If this became a pattern, I would address it with the charge nurse.", feedback: "Demonstrates professional integrity without being judgmental.", starBreakdown: { situation: "Colleague asked me to cover for an extra 30-minute break", task: "Maintain professional standards while preserving relationship", action: "Declined professionally, suggested speaking with charge nurse", result: "Colleague understood and spoke with charge nurse about scheduling" }, difficulty: "beginner" },
  { id: "sq-ip-beh-17", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You are floated to an unfamiliar unit and feel uncertain about the patient population and equipment.", question: "How would you ensure patient safety when floated to an unfamiliar unit?", exampleAnswer: "I would introduce myself to the charge nurse and ask for a brief orientation including equipment, emergency procedures, and unit-specific protocols. I would be transparent about my experience level and pair with an experienced nurse as a resource.", feedback: "Transparency about limitations and proactive orientation-seeking show maturity.", starBreakdown: { situation: "Floated from med-surg to a pediatric unit for the first time", task: "Provide safe care in an unfamiliar specialty setting", action: "Requested orientation, asked about pediatric protocols, partnered with experienced nurse", result: "Completed shift safely, learned new skills, received positive feedback" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-18", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You realize that a patient's allergy information was not updated in the electronic health record and a potentially allergenic medication was ordered.", question: "How would you handle discovering an allergy documentation gap?", exampleAnswer: "I would immediately hold the medication and verify the patient's allergies directly. I would update the allergy information in the EHR, notify the prescribing physician, and request an alternative if needed. I would file an incident report and inform the charge nurse.", feedback: "Proactive identification of safety gaps and systematic follow-through are essential.", starBreakdown: { situation: "Patient reported penicillin allergy not listed in chart; amoxicillin was ordered", task: "Prevent potential allergic reaction and correct documentation", action: "Held medication, verified allergy, updated EHR, notified physician", result: "Patient received safe alternative antibiotic, documentation corrected" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-19", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "A patient becomes verbally abusive and makes threatening statements toward you.", question: "How would you handle a patient who becomes verbally abusive or threatening?", exampleAnswer: "I would ensure my own safety first. I would maintain a calm, non-confrontational demeanor and set clear boundaries. If the behavior escalated, I would leave the room, call for security, and alert the charge nurse. I would document the behavior objectively and discuss a care plan modification.", feedback: "Safety first, then de-escalation, boundary-setting, and documentation.", starBreakdown: { situation: "Post-operative patient became verbally aggressive and threw a water pitcher", task: "Ensure safety while maintaining therapeutic approach", action: "Set firm boundaries, stepped back, called security, discussed with care team", result: "Security de-escalated, patient later apologized, behavior plan implemented" }, difficulty: "advanced" },
  { id: "sq-ip-beh-20", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You are asked to orient a new graduate nurse, but you only have two years of experience.", question: "How would you approach precepting when you are still relatively new?", exampleAnswer: "I would be honest about my experience level while expressing willingness. I would prepare by reviewing orientation checklists and competency requirements. I would share real experiences including lessons learned, focus on teaching critical thinking, and connect the new nurse with additional resources and mentors.", feedback: "Honesty about limitations combined with enthusiasm and resourcefulness is ideal.", starBreakdown: { situation: "Asked to precept a new grad with only 2 years of experience", task: "Provide effective orientation despite limited experience", action: "Prepared thoroughly, shared real experiences, connected orientee with mentors", result: "New nurse successfully completed orientation and cited me as a valuable preceptor" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-21", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "A patient's family member offers you a generous cash gift to thank you for the excellent care you provided.", question: "How would you handle receiving a gift from a patient or family member?", exampleAnswer: "I would sincerely thank them and explain that our facility policy does not allow staff to accept monetary gifts. I'd suggest alternative ways to express gratitude, such as writing a letter to hospital administration or donating to the hospital foundation.", feedback: "Gracious decline with redirection shows integrity and professional standards.", starBreakdown: { situation: "Patient's family offered a $200 cash gift after a complex recovery", task: "Decline gracefully while honoring their gratitude", action: "Thanked warmly, explained policy, suggested writing a commendation letter", result: "Family wrote a letter that was shared at the unit meeting" }, difficulty: "beginner" },
  { id: "sq-ip-beh-22", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You notice that a senior nurse consistently takes shortcuts during wound care, not following sterile technique properly.", question: "How would you address a senior colleague who is not following proper procedure?", exampleAnswer: "I would approach the situation respectfully, perhaps framing it as a learning opportunity for myself. I might say, 'I noticed a different approach to this wound care—can you help me understand the rationale?' If the practice was clearly unsafe, I would discuss my concerns privately and escalate to the charge nurse if needed.", feedback: "Respectful questioning combined with willingness to escalate when necessary.", starBreakdown: { situation: "Senior nurse consistently using non-sterile technique for wound dressing changes", task: "Address the unsafe practice without damaging the working relationship", action: "Asked respectful questions, then raised concern privately with charge nurse", result: "Unit conducted a wound care in-service, practices improved across the team" }, difficulty: "advanced" },
  { id: "sq-ip-beh-23", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "A patient asks you to pray with them before a procedure, but you do not share their religious beliefs.", question: "How would you respond to a patient requesting spiritual support?", exampleAnswer: "I would honor the patient's request as part of holistic care. I would be present, hold their hand if appropriate, and support their spiritual practice even if I do not share it. If I felt unable to participate directly, I would offer to call the hospital chaplain. The patient's comfort and emotional wellbeing are part of my care.", feedback: "Shows cultural sensitivity and commitment to holistic, patient-centered care.", starBreakdown: { situation: "Pre-surgical patient asked me to pray with them before being taken to the OR", task: "Support the patient's spiritual needs despite different beliefs", action: "Held the patient's hand, participated respectfully, offered chaplain services", result: "Patient felt supported and calm before surgery, expressed deep gratitude" }, difficulty: "beginner" },
  { id: "sq-ip-beh-24", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You made an error in your patient assessment documentation and only realize it hours later.", question: "How would you correct a documentation error you made earlier in your shift?", exampleAnswer: "I would follow proper documentation correction procedures. I would add a late entry noting the correct information, reference the time of the original entry, and explain the correction. I would never alter or delete the original entry. I would also inform the charge nurse if the error affected clinical decisions.", feedback: "Proper documentation correction and transparency are critical.", starBreakdown: { situation: "Documented wrong blood pressure reading for a hypertensive patient", task: "Correct the error transparently following documentation standards", action: "Added late entry with correct values, notified charge nurse, verified patient status", result: "Documentation corrected properly, patient's treatment was verified as appropriate" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-25", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "A patient with a history of drug abuse is requesting pain medication and you suspect drug-seeking behavior.", question: "How would you approach pain management for a patient with substance abuse history?", exampleAnswer: "I would assess the patient's pain objectively using validated pain scales and clinical indicators. I would advocate for adequate pain management regardless of their history. Pain is real and deserves treatment. I would communicate my assessment to the physician and collaborate on a pain management plan that may include non-opioid alternatives, scheduled rather than PRN dosing, and addiction medicine consultation.", feedback: "Avoids bias while maintaining clinical objectivity and patient advocacy.", starBreakdown: { situation: "Post-surgical patient with opioid use disorder requesting frequent PRN pain medication", task: "Provide adequate pain management without bias", action: "Assessed objectively, advocated for multimodal pain plan, consulted addiction medicine", result: "Patient received appropriate pain control with a structured plan that addressed both needs" }, difficulty: "advanced" },
  { id: "sq-ip-beh-26", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You are asked to work overtime for the third consecutive shift due to understaffing.", question: "How would you handle repeated requests to work mandatory overtime?", exampleAnswer: "I would assess my own fatigue level honestly and determine if I could safely care for patients. If I was too fatigued, I would communicate this clearly, citing patient safety concerns. I would offer to stay for a limited time while a replacement is found. I would also discuss the staffing issue with management and explore long-term solutions.", feedback: "Balances team support with self-care and patient safety awareness.", starBreakdown: { situation: "Third consecutive 16-hour shift requested due to chronic understaffing", task: "Protect patient safety while supporting the team", action: "Assessed fitness level, offered to stay 4 extra hours, raised staffing concerns with manager", result: "Management implemented float pool coverage, preventing future mandatory overtime" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-27", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "A patient's condition deteriorates rapidly and you need to call a rapid response team.", question: "Describe a time you had to respond to a rapidly deteriorating patient.", exampleAnswer: "I would activate the rapid response team immediately while beginning interventions within my scope. I would use SBAR to communicate the situation clearly: what I've observed, vital sign trends, what interventions I've already started, and what I think is happening. I would stay at the bedside, assist the response team, and ensure the family is informed.", feedback: "Clear SBAR communication and decisive action during emergencies are essential.", starBreakdown: { situation: "Medical patient's blood pressure dropped suddenly with altered mental status", task: "Recognize deterioration and activate emergency response", action: "Called rapid response, started fluid bolus per protocol, communicated via SBAR", result: "Patient stabilized, transferred to ICU, early intervention prevented cardiac arrest" }, difficulty: "advanced" },
  { id: "sq-ip-beh-28", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You receive end-of-shift report and realize the previous nurse did not complete several important tasks.", question: "How would you handle receiving an incomplete shift report?", exampleAnswer: "I would clarify what was and was not completed, prioritize the outstanding tasks by urgency, and begin addressing the most critical ones first. I would not complain about the previous nurse to others but would document what I found and complete the tasks. If this was a recurring pattern, I would address it with the charge nurse.", feedback: "Shows professionalism, prioritization, and focus on patient care over blame.", starBreakdown: { situation: "Received report with three patients missing scheduled medications and no wound assessments done", task: "Ensure all patient care needs were met safely", action: "Prioritized critical tasks, completed medications and assessments, documented findings", result: "All patients received necessary care, discussed pattern with charge nurse constructively" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-29", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "A family member posts on social media about the care their loved one is receiving at your facility, tagging the hospital and naming specific nurses.", question: "How would you handle a social media situation involving patient care?", exampleAnswer: "I would not respond to the post publicly or engage on social media about any patient situation. I would report the post to my charge nurse and the communications or public relations department. I would continue to provide excellent care to the patient and address any concerns the family has through proper channels.", feedback: "Understanding of social media boundaries and HIPAA implications is critical.", starBreakdown: { situation: "Family member posted negative review on Facebook naming specific nurses", task: "Protect patient privacy and professional reputation appropriately", action: "Did not engage online, reported to charge nurse and PR department, continued quality care", result: "PR team handled the response, family concerns addressed through proper channels" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-30", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You are caring for a patient from a cultural background very different from your own, and their family's expectations about care differ from standard practice.", question: "How would you provide culturally sensitive care when practices differ from your facility's norms?", exampleAnswer: "I would approach with genuine curiosity and respect for their cultural practices. I would ask the patient and family about their preferences and beliefs that affect their care. I would work with the care team to accommodate cultural practices whenever safe and possible, and explain when certain medical practices are necessary for safety. I would consult cultural liaison services if available.", feedback: "Genuine respect for cultural differences while maintaining safety standards.", starBreakdown: { situation: "Middle Eastern family requested only female nurses and specific dietary accommodations", task: "Honor cultural preferences while ensuring quality care delivery", action: "Coordinated female nursing assignments, worked with dietary services, educated team", result: "Family felt respected, patient's cultural needs were met, trust was established" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-31", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "During a code blue, you freeze momentarily and are unsure of your role.", question: "How would you handle freezing during an emergency situation?", exampleAnswer: "I would take a breath and focus on what I know. In a code, I would look for what role needs filling—compressions, medication administration, documentation, or airway management. I would announce my role clearly. If I was unsure, I would ask the code leader for direction. After the event, I would debrief with my team and practice mock codes to build confidence.", feedback: "Acknowledging the freeze while showing recovery and commitment to improvement.", starBreakdown: { situation: "First code blue as a new nurse, froze for 10 seconds upon entering the room", task: "Contribute effectively to the code despite initial hesitation", action: "Took a breath, identified an open role, began compressions, asked for guidance", result: "Performed effective compressions, debriefed afterward, practiced mock codes weekly" }, difficulty: "advanced" },
  { id: "sq-ip-beh-32", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "A patient confides in you that they have been experiencing domestic violence at home.", question: "How would you respond to a patient disclosing domestic violence?", exampleAnswer: "I would listen compassionately and validate their courage in sharing. I would ensure we are speaking privately. I would assess their immediate safety and document the disclosure carefully. I would connect them with social work services, provide information about domestic violence resources and hotlines, and develop a safety plan. I would follow mandatory reporting requirements as applicable.", feedback: "Shows compassion, proper assessment, resource mobilization, and legal awareness.", starBreakdown: { situation: "Female patient with recurrent injuries disclosed that her partner was abusive", task: "Provide immediate support and connect with appropriate resources", action: "Listened privately, assessed safety, contacted social worker, provided DV resources", result: "Patient connected with shelter services, safety plan developed, follow-up care arranged" }, difficulty: "advanced" },
  { id: "sq-ip-beh-33", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You are the charge nurse and two staff members are having a loud disagreement in front of patients.", question: "How would you handle staff conflict occurring in patient care areas?", exampleAnswer: "I would immediately and calmly redirect both staff members to a private area. I would remind them that professional behavior in patient care areas is essential. I would listen to both perspectives, mediate the disagreement, and establish expectations for professional conduct. I would follow up with each person individually and document the incident if necessary.", feedback: "Swift intervention to protect the patient care environment while fairly addressing the issue.", starBreakdown: { situation: "Two CNAs arguing loudly near patient rooms about assignment fairness", task: "Stop the public conflict and address the underlying issue", action: "Redirected to private area, listened to both sides, mediated fairly, set expectations", result: "Conflict resolved, patients were not further disturbed, team norms reinforced" }, difficulty: "advanced" },
  { id: "sq-ip-beh-34", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "A student nurse is shadowing you and makes a mistake during a patient interaction.", question: "How would you handle a student nurse's error during clinical?", exampleAnswer: "I would intervene immediately if patient safety was at risk. I would correct the situation calmly and professionally without embarrassing the student in front of the patient. Afterward, I would debrief privately with the student, explain what went wrong, demonstrate the correct approach, and let them practice again with supervision. I would frame it as a learning opportunity.", feedback: "Patient safety first, followed by supportive, educational debriefing.", starBreakdown: { situation: "Nursing student did not verify patient identity before medication administration", task: "Ensure patient safety while providing an educational experience", action: "Gently stopped the student, demonstrated proper identification, debriefed privately", result: "Student learned the lesson, no patient harm occurred, student became more careful" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-35", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You are assigned to a patient who has the same condition that recently affected a close family member of yours.", question: "How would you manage emotional triggers when caring for patients with personal relevance?", exampleAnswer: "I would assess my ability to provide objective, quality care. If I felt I could manage my emotions professionally, I would proceed while being mindful of my boundaries. If I felt it would compromise care, I would privately speak with my charge nurse about a reassignment. I would use self-care strategies and debrief with a trusted colleague or counselor after my shift.", feedback: "Self-awareness and honest assessment of emotional capacity show professional maturity.", starBreakdown: { situation: "Assigned to a young cancer patient similar in age to my sibling who had cancer", task: "Provide quality care while managing personal emotional response", action: "Assessed my capacity, proceeded with care, debriefed with nurse counselor after shift", result: "Patient received excellent care, I processed my emotions in a healthy way" }, difficulty: "advanced" },
  { id: "sq-ip-beh-36", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "During handoff, the outgoing nurse gives you minimal information and rushes through the report.", question: "What would you do if you received an inadequate shift handoff?", exampleAnswer: "I would stop the outgoing nurse and ask specific questions about each patient's condition, recent changes, pending labs, and care priorities. I would use a structured handoff tool like SBAR to ensure I get all critical information. I would verify IV fluids, drips, and scheduled medications independently. If this was a recurring issue, I would discuss it with the charge nurse.", feedback: "Taking ownership of your patient information gathering is essential for safety.", starBreakdown: { situation: "Outgoing nurse rushed through report in 5 minutes for 6 patients", task: "Ensure I had adequate information for safe care", action: "Asked targeted questions, reviewed charts independently, verified critical details", result: "Identified a missed critical lab value and caught a discontinued IV order" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-37", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "A colleague consistently takes credit for your work during team meetings.", question: "How would you address a colleague who takes credit for your contributions?", exampleAnswer: "I would first document my contributions clearly through emails and written summaries. During meetings, I would proactively present my own work and ideas. If the behavior continued, I would have a private conversation with the colleague about the impact of their actions. I would keep my manager informed of my contributions through regular updates.", feedback: "Professional self-advocacy without being confrontational or petty.", starBreakdown: { situation: "Colleague presented my patient education initiative as their idea in a unit meeting", task: "Ensure proper credit while maintaining the working relationship", action: "Spoke privately with the colleague, started presenting my own work directly", result: "Colleague acknowledged the mistake, future contributions were properly attributed" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-38", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You are asked to perform a procedure you have only observed but never done independently.", question: "How would you handle being asked to perform a procedure outside your comfort level?", exampleAnswer: "I would be transparent about my experience level and say, 'I have observed this procedure but have not performed it independently. I would feel more comfortable having supervision for my first time.' I would ask an experienced colleague or my charge nurse to observe and guide me. Patient safety depends on honest self-assessment.", feedback: "Transparency about competency limitations protects patients and shows integrity.", starBreakdown: { situation: "Asked to insert a nasogastric tube without having done one independently", task: "Perform the procedure safely despite limited experience", action: "Disclosed experience level, requested supervision, performed under guidance", result: "Procedure completed safely, gained confidence for future independent performance" }, difficulty: "beginner" },
  { id: "sq-ip-beh-39", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "A patient complains that a previous nurse was rude and uncaring, and they want to file a formal complaint.", question: "How would you respond to a patient who wants to complain about a colleague?", exampleAnswer: "I would listen to the patient's concerns with empathy and validate their feelings. I would not defend or criticize the other nurse. I would provide information about the patient relations department and how to file a formal complaint if they wished. I would focus on providing excellent care moving forward and document the patient's concern.", feedback: "Empathetic listening, neutrality about colleagues, and proper referral to complaint channels.", starBreakdown: { situation: "Patient upset about previous nurse's dismissive attitude toward their pain", task: "Address the patient's concerns professionally without taking sides", action: "Listened empathetically, provided complaint process information, focused on their current care", result: "Patient felt heard, filed a constructive complaint, received excellent care going forward" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-40", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You are on a unit with a toxic workplace culture where new nurses are not welcomed or supported.", question: "How would you navigate a hostile work environment as a new graduate?", exampleAnswer: "I would focus on building individual relationships rather than trying to change the entire culture at once. I would seek out allies and mentors who are supportive. I would document any incidents of bullying or harassment. I would maintain my professionalism and work ethic consistently. If the environment was truly unsafe, I would escalate to HR and consider transferring to a healthier unit.", feedback: "Resilience combined with self-advocacy and knowing when to escalate.", starBreakdown: { situation: "Experienced nurses on the unit excluded new graduates from team activities and withheld help", task: "Establish myself professionally in a hostile environment", action: "Built relationships individually, found a mentor, documented incidents, discussed with manager", result: "Manager addressed the culture, several supportive relationships developed, environment improved" }, difficulty: "advanced" },
  { id: "sq-ip-beh-41", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You accidentally stick yourself with a used needle while caring for a patient.", question: "What steps would you take immediately after a needlestick injury?", exampleAnswer: "I would immediately wash the area with soap and water, then report the injury to my charge nurse. I would complete an incident report and go to employee health for a baseline blood draw and assessment. I would identify the source patient so their blood could be tested with consent. I would follow my facility's post-exposure protocol including any prophylactic medications.", feedback: "Immediate and systematic response to occupational exposure is critical.", starBreakdown: { situation: "Stuck by needle used for insulin administration on a patient with unknown blood status", task: "Follow post-exposure protocol immediately", action: "Washed wound, reported to charge nurse, went to employee health, completed testing", result: "Received appropriate prophylaxis, source patient tested negative, follow-up completed" }, difficulty: "beginner" },
  { id: "sq-ip-beh-42", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "A physician speaks to you disrespectfully in front of other staff members.", question: "How would you handle being spoken to disrespectfully by a physician?", exampleAnswer: "I would remain calm and professional in the moment. I would not engage in a public confrontation. After the situation, I would approach the physician privately and say, 'I appreciate your clinical expertise, but I felt the way you spoke to me earlier was disrespectful. I want to work together effectively, and I'd appreciate being treated with the same respect I show you.' If the behavior continued, I would escalate to my manager.", feedback: "Calm professionalism followed by assertive private conversation.", starBreakdown: { situation: "Attending physician berated me loudly in front of patients for calling about a non-urgent issue", task: "Address the disrespect while maintaining a professional working relationship", action: "Stayed calm, addressed it privately later with clear I-statements", result: "Physician apologized, our working relationship actually improved with clearer communication" }, difficulty: "advanced" },
  { id: "sq-ip-beh-43", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You realize midway through your shift that you are developing symptoms of illness.", question: "What would you do if you started feeling unwell during your shift?", exampleAnswer: "I would assess my symptoms and determine if I could safely continue patient care. If my symptoms included fever, vomiting, or anything that could be contagious, I would immediately inform my charge nurse. I would avoid direct patient contact until a decision was made about my status. Patient safety and infection control are the priorities.", feedback: "Self-awareness and putting patient safety above personal commitment to finish the shift.", starBreakdown: { situation: "Developed fever and chills three hours into a 12-hour shift", task: "Ensure patient safety while managing my own illness", action: "Informed charge nurse, avoided direct patient contact, helped with non-patient tasks while replacement was found", result: "Replacement nurse arrived within 2 hours, patients were not exposed to illness" }, difficulty: "beginner" },
  { id: "sq-ip-beh-44", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You are assigned to care for a patient who has been incarcerated and has guards present in the room.", question: "How would you provide equitable care to an incarcerated patient?", exampleAnswer: "I would treat the patient with the same dignity and quality of care I provide to all patients. I would maintain patient privacy by asking guards to step outside during examinations when safe to do so. I would not make assumptions about the patient based on their legal status. Their medical needs are my responsibility regardless of their circumstances.", feedback: "Demonstrates commitment to equitable care and professional ethics.", starBreakdown: { situation: "Assigned to care for a patient in restraints with two armed guards present", task: "Provide dignified, quality care despite the unusual circumstances", action: "Introduced myself warmly, requested privacy for assessment, treated with full respect", result: "Patient received thorough care, expressed appreciation for being treated like any other patient" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-45", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "Your manager asks you to precept an internationally educated nurse who has different clinical training and practices.", question: "How would you precept a nurse from a different educational background?", exampleAnswer: "I would approach the experience with respect for their existing knowledge and clinical experience. I would identify the gaps between their training and our facility's practices rather than assuming they know nothing. I would focus on policy differences, documentation systems, and cultural aspects of care in this setting. I would learn from their perspective too.", feedback: "Cultural humility and recognition of diverse clinical knowledge.", starBreakdown: { situation: "Precepting a nurse from the Philippines with 5 years of experience but new to North American practice", task: "Help them adapt to new systems while respecting their expertise", action: "Focused on system differences, built on existing knowledge, learned from their experience", result: "Nurse transitioned successfully, brought valuable perspectives to the team" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-46", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "A patient asks you about your personal life, specifically whether you are married and have children.", question: "How do you maintain professional boundaries when patients ask personal questions?", exampleAnswer: "I would redirect the conversation warmly. I might briefly acknowledge the question with a general response and then redirect to their care: 'I appreciate the interest! Let me check on how you are feeling right now.' Maintaining professional boundaries does not mean being cold—it means keeping the focus on the patient's wellbeing.", feedback: "Warm redirection without oversharing personal information.", starBreakdown: { situation: "Elderly patient frequently asked personal questions during care interactions", task: "Maintain professional boundaries while keeping the therapeutic relationship warm", action: "Gave brief, general responses and redirected to patient's interests and care", result: "Patient felt connected and cared for without boundary violations" }, difficulty: "beginner" },
  { id: "sq-ip-beh-47", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You witness a fall in the hallway but were not the nurse assigned to the patient who fell.", question: "What would you do if you witnessed a patient fall outside your assignment?", exampleAnswer: "I would immediately respond by ensuring the patient is safe and assessing for injuries. I would call for help and stay with the patient until their assigned nurse arrived. I would not attempt to move the patient if there was concern for spinal injury. I would assist with documentation as a witness and help implement fall prevention measures.", feedback: "Demonstrates that patient safety is everyone's responsibility regardless of assignment.", starBreakdown: { situation: "Witnessed an elderly patient fall in the hallway near the nursing station", task: "Provide immediate assistance even though not the assigned nurse", action: "Assessed for injuries, called for help, stayed with patient, provided witness account", result: "Patient had no serious injuries, fall prevention measures were updated" }, difficulty: "beginner" },
  { id: "sq-ip-beh-48", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You are asked to transfer a patient and the receiving nurse seems annoyed about accepting the admission.", question: "How would you handle resistance from a receiving nurse during patient transfer?", exampleAnswer: "I would remain professional and provide a thorough, organized report using SBAR format. I would not take their attitude personally—they may be overwhelmed with their own workload. I would focus on ensuring a safe handoff by providing all relevant clinical information. If the resistance prevented safe care transition, I would involve the charge nurse.", feedback: "Professionalism in difficult interpersonal situations and commitment to safe handoffs.", starBreakdown: { situation: "Receiving ICU nurse was visibly annoyed about accepting my post-op patient", task: "Ensure safe patient transfer despite interpersonal friction", action: "Gave thorough SBAR report, offered to help with initial setup, remained professional", result: "Patient safely transferred, receiving nurse acknowledged the quality of the handoff" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-49", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "You discover that your facility's electronic health record system is down and you need to document patient care.", question: "How would you manage patient care when the EHR system goes down?", exampleAnswer: "I would switch to downtime documentation procedures—typically paper charting forms that should be readily available on the unit. I would continue all patient care as usual and document accurately on paper. I would label all paper documentation clearly with patient identifiers. Once the system was restored, I would enter all paper documentation into the electronic record according to facility policy.", feedback: "Adaptability and knowledge of downtime procedures are essential.", starBreakdown: { situation: "EHR system crashed during a busy night shift with 5 patients", task: "Maintain accurate documentation using downtime procedures", action: "Used paper downtime forms, documented all care in real-time, transferred to EHR when restored", result: "No documentation gaps, all patient care was accurately recorded" }, difficulty: "intermediate" },
  { id: "sq-ip-beh-50", formatType: "behavioral", categoryGroup: "interview_preparation", subcategory: "behavioral", scenarioPrompt: "After a particularly difficult patient death, you feel emotionally overwhelmed and are struggling to continue your shift.", question: "How would you cope with the emotional impact of a patient death during your shift?", exampleAnswer: "I would allow myself a few minutes to process my emotions—stepping into a private area if possible. I would inform my charge nurse that I need a brief break. I would use coping strategies like deep breathing and grounding techniques. I would reach out to a trusted colleague for support. After the shift, I would utilize available resources like employee assistance programs or peer support groups.", feedback: "Self-awareness, self-care, and willingness to seek support show emotional intelligence.", starBreakdown: { situation: "Young trauma patient died despite resuscitation efforts during my second month of practice", task: "Process grief while continuing to provide safe care for other patients", action: "Took a brief break, spoke with charge nurse, received peer support, used EAP later", result: "Completed the shift safely, processed the grief with professional support" }, difficulty: "advanced" },
];
